import{_ as n,c as t,a1 as i,o as a}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Công cụ","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/8-social-engineering/X-Tools.md","filePath":"vi/categories/ethical-hacking-labs/8-social-engineering/X-Tools.md"}'),e={name:"vi/categories/ethical-hacking-labs/8-social-engineering/X-Tools.md"};function r(c,h,s,g,o,p){return a(),t("div",null,h[0]||(h[0]=[i('<h1 id="cong-cu" tabindex="-1">Công cụ <a class="header-anchor" href="#cong-cu" aria-label="Permalink to &quot;Công cụ&quot;">​</a></h1><h2 id="phat-hien-trang-phishing-bang-tien-ich-netcraft" tabindex="-1">Phát hiện trang Phishing bằng tiện ích NetCraft <a class="header-anchor" href="#phat-hien-trang-phishing-bang-tien-ich-netcraft" aria-label="Permalink to &quot;Phát hiện trang Phishing bằng tiện ích NetCraft&quot;">​</a></h2><p>Tiện ích mở rộng trình duyệt chống phishing của Netcraft cung cấp thông tin toàn diện về trang web và bảo vệ chống phishing khi duyệt web. Người dùng cũng có thể sử dụng tiện ích mở rộng này để báo cáo các URL mà họ cho là độc hại cho Netcraft.</p><p><a href="https://netcraft.app/browser-extension/" target="_blank" rel="noreferrer">https://netcraft.app/browser-extension/</a><img src="https://netcraft.app/assets/img/screenshots/extension/blocked.png" alt="NetCraft"></p><h2 id="phat-hien-phishing-bang-phishtank" tabindex="-1">Phát hiện Phishing bằng PhishTank <a class="header-anchor" href="#phat-hien-phishing-bang-phishtank" aria-label="Permalink to &quot;Phát hiện Phishing bằng PhishTank&quot;">​</a></h2><p>PhishTank là một trung tâm cộng tác về dữ liệu và thông tin về phishing trên Internet. Ngoài ra, PhishTank cung cấp một API mở cho các nhà phát triển và nhà nghiên cứu tích hợp dữ liệu chống phishing vào ứng dụng của họ miễn phí.</p><p><a href="https://www.phishtank.com/" target="_blank" rel="noreferrer">https://www.phishtank.com/</a></p><h2 id="wifiphisher" tabindex="-1">Wifiphisher <a class="header-anchor" href="#wifiphisher" aria-label="Permalink to &quot;Wifiphisher&quot;">​</a></h2><p>Wifiphisher là một công cụ bảo mật thực hiện các cuộc tấn công phishing tự động chống lại mạng Wi-Fi nhằm thu thập thông tin đăng nhập hoặc lây nhiễm &#39;malware&#39; cho nạn nhân. Đây là một cuộc tấn công kỹ thuật xã hội có thể được sử dụng để thu thập cụm mật khẩu WPA/WPA2 và không giống như các phương pháp khác, nó không yêu cầu brute forcing. Sau khi đạt được vị trí man-in-the-middle bằng cách sử dụng cuộc tấn công Evil Twin, Wifiphisher chuyển hướng tất cả các yêu cầu HTTP đến trang phishing do kẻ tấn công kiểm soát.</p><p><a href="https://tools.kali.org/wireless-attacks/wifiphisher" target="_blank" rel="noreferrer">https://tools.kali.org/wireless-attacks/wifiphisher</a></p><h2 id="spf-speedphish-framework" tabindex="-1">SPF - SpeedPhish Framework <a class="header-anchor" href="#spf-speedphish-framework" aria-label="Permalink to &quot;SPF - SpeedPhish Framework&quot;">​</a></h2><p>SPF (SpeedPhish Framework) là một công cụ Python được thiết kế cho phép trinh sát nhanh và triển khai các bài tập phishing kỹ thuật xã hội đơn giản.</p><p><a href="https://github.com/tatanus/SPF" target="_blank" rel="noreferrer">https://github.com/tatanus/SPF</a></p>',13)]))}const d=n(e,[["render",r]]);export{m as __pageData,d as default};
